const fs = require('fs'), path = require('path');
const BASE = 'C:/Users/34529/WorkBuddy/2026-05-21-19-39-57/anchorfact/content';
let id = 111;
function slug(t){return t.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')}
function add({title,category,lang='en',sources,tldr,body,comp=0.82}){
  const i='kb-2026-'+String(id++).padStart(5,'0'),f=slug(title)+'.md',d=path.join(BASE,category);
  if(!fs.existsSync(d))fs.mkdirSync(d,{recursive:true});
  const s=sources.map(s=>`  - title:"${s.title}"\n`+(s.authors?`    authors:[${s.authors.map(a=>`"${a}"`).join(',')}]\n`:'')+`    type:"${s.type}"\n`+(s.year?`    year:${s.year}\n`:'')+`    url:"${s.url}"\n`+(s.inst?`    institution:"${s.inst}"\n`:'')).join('');
  const fm=`---\nid:"${i}"\ntitle:"${title}"\nschema_type:"TechArticle"\ncategory:"${category}"\nlanguage:"${lang}"\nconfidence:"high"\nlast_verified:"2026-05-22"\ngeneration_method:"ai_assisted"\nai_models:["claude-opus"]\nderived_from_human_seed:true\nprimary_sources:\n${s}completeness:${comp}\nai_citations:\n  last_citation_check:"2026-05-22"\n---\n\n## TL;DR\n\n${tldr}\n\n## Core Explanation\n\n${body}\n\n## Further Reading\n\n${sources.map(s=>`- [${s.title}](${s.url})`).join('\n')}\n`;
  fs.writeFileSync(path.join(d,f),fm); return {i,title,category};
}
let a=[];

// Security (15)
[
{t:"HTTPS/TLS",c:"computer-science",src:[{t:"RFC 8446 — TLS 1.3",tp:"standard",y:2018,u:"https://www.rfc-editor.org/rfc/rfc8446",inst:"IETF"}],tl:"HTTPS (HTTP over TLS) encrypts HTTP traffic between client and server, providing confidentiality (encryption), integrity (tamper detection), and authentication (server identity via certificates). TLS 1.3 (RFC 8446, 2018) reduced the handshake from 2-RTT to 1-RTT (0-RTT on resumption) and removed obsolete algorithms.",b:"TLS handshake: ClientHello → ServerHello + Certificate → Key exchange (ECDHE) → Finished. Certificates (X.509) are issued by Certificate Authorities (CAs) and contain the domain name, public key, validity period. Modern TLS 1.3 supports only AEAD ciphers (AES-GCM, ChaCha20-Poly1305). HSTS (`Strict-Transport-Security` header) forces HTTPS usage."},
{t:"SQL Injection",c:"computer-science",src:[{t:"OWASP Top 10 — Injection",tp:"documentation",y:2021,u:"https://owasp.org/Top10/A03_2021-Injection/",inst:"OWASP"}],tl:"SQL Injection is a code injection attack where malicious SQL statements are inserted into application queries through user input. It ranked #3 on the OWASP Top 10 (2021) and can lead to data theft, data loss, and complete system compromise.",b:"Prevention: parameterized queries (prepared statements), stored procedures, input validation, least-privilege database accounts. Never concatenate user input into SQL strings — this is the single rule that prevents SQL injection. Use placeholders: SELECT * FROM users WHERE name = ? (MySQL) or $1 (PostgreSQL). ORMs (Prisma, SQLAlchemy) provide parameterized queries by default."},
{t:"Cross-Site Scripting (XSS)",c:"computer-science",src:[{t:"OWASP Top 10 — Cross-Site Scripting",tp:"documentation",y:2021,u:"https://owasp.org/www-community/attacks/xss/",inst:"OWASP"}],tl:"XSS is an injection attack where malicious scripts are injected into trusted websites, executing in victims' browsers. Three types: Stored (persistent, in database), Reflected (in URL parameters), DOM-based (client-side JavaScript vulnerability). Prevention: output encoding, Content Security Policy (CSP), input validation.",b:"Reflected XSS: attacker crafts URL with script in query parameter, victim clicks link, script executes in victim's context. Stored XSS: script stored in database (comment, profile), executed whenever any user views the page. DOM XSS: client-side code writes user input to innerHTML without sanitization. Modern frameworks (React/Vue/Angular) auto-escape by default, reducing but not eliminating risk."},
{t:"Cross-Site Request Forgery (CSRF)",c:"computer-science",src:[{t:"OWASP — Cross-Site Request Forgery",tp:"documentation",y:2021,u:"https://owasp.org/www-community/attacks/csrf",inst:"OWASP"}],tl:"CSRF forces authenticated users to execute unwanted actions on a web application. The attacker tricks the victim's browser into sending a request that the application treats as legitimate because it carries the user's session cookie. Prevention: anti-CSRF tokens, SameSite cookies, custom headers.",b:"SameSite cookie attribute (2020+): `Strict` (never sent cross-site), `Lax` (default since Chrome 80, sent on top-level navigation GET), `None` (always sent, requires Secure). Modern frameworks (Laravel, Django, Rails) include CSRF protection by default. Double-submit cookie pattern: send token in both cookie and request header."},
{t:"Authentication vs Authorization",c:"computer-science",src:[{t:"NIST SP 800-63 — Digital Identity Guidelines",tp:"standard",y:2022,u:"https://pages.nist.gov/800-63-3/",inst:"NIST"}],tl:"Authentication verifies identity (who you are), while authorization determines permissions (what you can do). Authentication factors: something you know (password), have (token), are (biometrics). Multi-Factor Authentication (MFA) requires two or more factors. Authorization models: RBAC (Role-Based Access Control), ABAC (Attribute-Based), ReBAC (Relationship-Based).",b:"Session management: after authentication, a session token (cookie, JWT) maintains state across requests. OAuth 2.0 and OpenID Connect (OIDC) are the modern standards for delegated authentication/authorization. Key principle: never roll your own authentication — use battle-tested libraries and follow current NIST guidelines."},
{t:"Public Key Cryptography",c:"computer-science",src:[{t:"Handbook of Applied Cryptography",tp:"book",y:1996,u:"https://cacr.uwaterloo.ca/hac/",inst:"CRC Press"}],tl:"Public-key (asymmetric) cryptography uses key pairs: public key (shared freely) and private key (kept secret). It enables encryption (only private key can decrypt), digital signatures (authenticity + integrity), and key exchange (establish shared secrets). RSA (1977), ECC (1985), and Ed25519 (2011) are the dominant algorithms.",b:"RSA: security based on difficulty of factoring large numbers. ECC: smaller keys for equivalent security — 256-bit ECC ≈ 3072-bit RSA. Elliptic Curve Diffie-Hellman (ECDH) is the standard key exchange. Key sizes: 2048-bit RSA (minimum), 4096-bit RSA (recommended long-term), 256-bit ECC. Quantum computing threatens both RSA and ECC — NIST is standardizing post-quantum cryptography (2024)."},
{t:"Hashing Algorithms",c:"computer-science",src:[{t:"NIST FIPS 180-4 — Secure Hash Standard (SHS)",tp:"standard",y:2015,u:"https://csrc.nist.gov/publications/detail/fips/180/4/final",inst:"NIST"}],tl:"Cryptographic hash functions map arbitrary data to fixed-size digests (fingerprints). Key properties: preimage resistance (cannot reverse), second preimage resistance (cannot find different input with same hash), collision resistance (cannot find any two inputs with same hash). SHA-256 (32 bytes) is the current standard; SHA-3 (Keccak) is the next generation.",b:"SHA-1 (broken, 2017 collision demonstrated). MD5 (completely broken). SHA-2 family: SHA-224, SHA-256, SHA-384, SHA-512 (all considered secure). SHA-3 is not a replacement but an alternative with different internal structure (sponge construction). Password hashing uses specialized functions: bcrypt (adaptive cost), scrypt (memory-hard), Argon2 (winner of PHC, 2015 — memory-hard + side-channel resistant)."},
{t:"DDoS Attack",c:"computer-science",src:[{t:"NIST SP 800-189 — DDoS Defense",tp:"standard",y:2022,u:"https://csrc.nist.gov/publications/detail/sp/800-189/final",inst:"NIST"}],tl:"A Distributed Denial-of-Service (DDoS) attack overwhelms a target with traffic from multiple sources, making it unavailable to legitimate users. Types: volumetric (saturate bandwidth), protocol (exploit TCP/SYN, DNS amplification), application-layer (HTTP flood, Slowloris). Defense: CDN scrubbing (Cloudflare, Akamai), rate limiting, anycast distribution.",b:"SYN flood: attacker sends TCP SYN packets but never completes handshake, exhausting server's connection table. DNS amplification: attacker spoofs victim's IP, sends small queries to open DNS resolvers that reply with large responses. Mitigation: SYN cookies, connection rate limiting, IP reputation filtering. Cloud providers (AWS Shield, Google Cloud Armor) provide built-in DDoS protection."},
{t:"Zero Trust Architecture",c:"computer-science",src:[{t:"NIST SP 800-207 — Zero Trust Architecture",tp:"standard",y:2020,u:"https://csrc.nist.gov/publications/detail/sp/800-207/final",inst:"NIST"}],tl:"Zero Trust is a security model that assumes no implicit trust — verify every access request regardless of network location (internal or external). Core principles: never trust, always verify; least privilege access; assume breach. Mandated by US Executive Order 14028 (2021) for federal agencies.",b:"Key components: microsegmentation (network isolation), identity-aware proxies, continuous authentication, encryption everywhere. Replaces the castle-and-moat model (trusted internal network, untrusted external). Implementation frameworks: Google BeyondCorp (origin of Zero Trust, 2014), NIST SP 800-207. ZTNA (Zero Trust Network Access) replaces traditional VPNs."},
{t:"OWASP Top 10",c:"computer-science",src:[{t:"OWASP Top 10 (2021)",tp:"standard",y:2021,u:"https://owasp.org/Top10/",inst:"OWASP Foundation"}],tl:"The OWASP Top 10 is the de facto standard for web application security awareness, listing the ten most critical security risks. Updated periodically (last: 2021), it guides security testing, code review, and developer education worldwide. The 2021 edition shifted from vulnerability categories to risk-based categories.",b:"2021 Top 10: A01 Broken Access Control, A02 Cryptographic Failures, A03 Injection, A04 Insecure Design, A05 Security Misconfiguration, A06 Vulnerable Components, A07 Auth Failures, A08 Software Integrity Failures, A09 Logging/Monitoring Failures, A10 SSRF. This list represents a broad consensus about critical risks — every web developer should be familiar with it."},
{t:"Firewall",c:"computer-science",src:[{t:"NIST SP 800-41 — Firewalls",tp:"standard",y:2020,u:"https://csrc.nist.gov/publications/detail/sp/800-41/rev-1/final",inst:"NIST"}],tl:"A firewall is a network security system that monitors and controls incoming/outgoing traffic based on predetermined rules. Types: packet filtering (stateless, layer 3/4), stateful inspection (tracks connection state), application-layer (WAF, layer 7), next-generation (NGFW, combines all).",b:"Packet filters examine source/destination IP, port, protocol. Stateful firewalls maintain connection tables and can make contextual decisions (allow reply packets for established connections). WAF (Web Application Firewall) inspects HTTP requests for SQL injection, XSS, and other application attacks. Modern cloud-native approaches: security groups (AWS), network policies (Kubernetes)."},
{t:"VPN (Virtual Private Network)",c:"computer-science",src:[{t:"NIST SP 800-77 — IPsec VPNs",tp:"standard",y:2020,u:"https://csrc.nist.gov/publications/detail/sp/800-77/rev-1/final",inst:"NIST"}],tl:"A VPN creates an encrypted tunnel between a device and a network, protecting data in transit and masking the user's IP address. Protocols: IPsec (network layer, site-to-site), OpenVPN/WireGuard (application layer, client-to-server). WireGuard (2020, Linux kernel since 5.6) is faster and simpler than IPsec/OpenVPN.",b:"WireGuard uses state-of-the-art cryptography: Curve25519 (key exchange), ChaCha20 (encryption), Poly1305 (authentication), BLAKE2s (hashing). Only ~4000 lines of code vs. ~600K for OpenVPN — dramatically smaller attack surface. VPNs do NOT provide anonymity — they shift trust from ISP to VPN provider. Tor (onion routing) provides stronger anonymity via three-hop circuit."},
{t:"SSH Protocol",c:"computer-science",src:[{t:"RFC 4251 — SSH Protocol Architecture",tp:"standard",y:2006,u:"https://www.rfc-editor.org/rfc/rfc4251",inst:"IETF"}],tl:"SSH (Secure Shell) is a cryptographic network protocol for secure remote login and command execution over unsecured networks, standardized as IETF RFC 4251 (2006). It replaced insecure protocols (telnet, rlogin, rsh). SSH uses public-key cryptography for authentication and symmetric encryption for session data.",b:"SSH handshake: key exchange (Diffie-Hellman) → host authentication (server key fingerprint) → user authentication (password, public key, or keyboard-interactive) → encrypted session. SSH keys: `ssh-keygen -t ed25519` (recommended). `~/.ssh/authorized_keys` lists trusted public keys. SSH agent forwarding enables key use across jumps without copying private keys — use with caution (Agent hijacking risk)."},
{t:"Docker Security Best Practices",c:"computer-science",src:[{t:"Docker Security Documentation",tp:"documentation",y:2025,u:"https://docs.docker.com/engine/security/",inst:"Docker Inc."}],tl:"Docker containers share the host kernel, making security critical. Best practices: run as non-root user, use minimal base images (distroless, alpine), scan images for vulnerabilities, limit capabilities, use read-only root filesystems, enable seccomp/AppArmor profiles.",b:"`USER 1000` in Dockerfile (never run as root). `docker scan` or Trivy for vulnerability scanning. `--read-only` flag makes rootfs immutable. `--cap-drop=ALL --cap-add=NET_BIND_SERVICE` limits Linux capabilities. Docker Bench Security checks against CIS Benchmark. Podman (daemonless, rootless by default) and gVisor (user-space kernel) provide stronger isolation."},
{t:"OWASP API Security Top 10",c:"computer-science",src:[{t:"OWASP API Security Top 10 (2023)",tp:"standard",y:2023,u:"https://owasp.org/API-Security/",inst:"OWASP Foundation"}],tl:"The OWASP API Security Top 10 is a dedicated list of the most critical API security risks, separate from the general web application Top 10. It addresses API-specific threats: broken object-level authorization, broken authentication, excessive data exposure, lack of rate limiting.",b:"API1:2023 Broken Object Level Authorization (BOLA) — user accesses other users' data by modifying ID in URL. API2:2023 Broken Authentication — weak JWT validation, no MFA. API3:2023 Broken Object Property Level Authorization — mass assignment vulnerabilities. API4:2023 Unrestricted Resource Consumption — no rate limiting enables DoS. Every API developer should review this list."},
].forEach(x=>{a.push(add(Object.assign({title:x.t,category:x.c,sources:x.src,tldr:x.tl,body:x.b},x)))});

// Data Structures & Algorithms (15)
[
{t:"Array Data Structure",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)"},{t:"Algorithms (4th Edition)"}].map(s=>({...s,tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"})),tl:"An array is a contiguous block of memory storing elements of the same type, accessible by index in O(1) time. It is the most fundamental data structure. Dynamic arrays (JavaScript Array, C++ vector) use geometric expansion for amortized O(1) append.",b:"Key operations: access O(1), search O(n). Dynamic arrays amortize resizing by doubling capacity. Multi-dimensional arrays stored in row-major (C) or column-major (Fortran). Cache locality makes arrays fast — each cache miss loads 64 bytes (16 ints on 64-bit). Drawbacks: fixed size (static) or expensive resize (dynamic)."},
{t:"Linked List",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"A linked list is a linear collection of nodes, each containing data and a pointer. O(1) insert/delete at known position, O(n) random access. Variants: singly-linked, doubly-linked, circular. Poor cache locality but dynamic sizing is trivial.",b:"Singly-linked: data + next pointer. Doubly-linked: data + next + prev. JavaScript doesn't have built-in linked lists — Array is always used due to cache performance. Linked lists shine when frequent insertions/deletions at arbitrary positions are needed and memory is fragmented."},
{t:"Hash Table",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"A hash table maps keys to values with average O(1) operations. Powers JavaScript Objects, Python dicts, database indexes. Collision resolution: chaining (linked lists) or open addressing (probing). Rehashing triggers at ~75% load factor.",b:"Hash function: maps key to integer index. Good hash functions minimize collisions and are fast (non-cryptographic: MurmurHash, xxHash). Cryptographic hashes (SHA) are unnecessary and slow for hash tables. Separate chaining is simpler but uses more memory; open addressing is cache-friendly but degrades at high load."},
{t:"Binary Search Tree",c:"computer-science",src:[{t:"Algorithms (4th Edition)",tp:"book",y:2011,u:"https://algs4.cs.princeton.edu/",inst:"Princeton"}],tl:"A BST stores keys in left < parent < right order. Average O(log n) operations when balanced, degrade to O(n) if unbalanced. Self-balancing variants: AVL, Red-Black, B-tree. BST is foundation for sorted maps/sets.",b:"Traversals: inorder (sorted), preorder (serialization), postorder (deletion). Self-balancing: AVL (strict balance, ~1.44 log n height), Red-Black (relaxed, ≤2 log n height, fewer rotations). Java TreeMap, C++ std::map use Red-Black trees."},
{t:"Heap / Priority Queue",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"A heap is a complete binary tree with the heap property (parent ≤ children for min-heap). O(1) peek, O(log n) insert/extract. Array-based representation: children of i are 2i+1, 2i+2.",b:"Binary heap is the most common implementation. Heapify (construction): O(n) bottom-up. Heapsort: build heap + n extractions = O(n log n) in-place. Priority queues in Dijkstra, job scheduling, event simulation. Fibonacci heap achieves O(1) insert, amortized O(log n) extract."},
{t:"Graph & BFS/DFS",c:"computer-science",src:[{t:"Algorithms (4th Edition)",tp:"book",y:2011,u:"https://algs4.cs.princeton.edu/",inst:"Princeton"}],tl:"A graph G=(V,E) models networks. BFS (queue) finds shortest paths in unweighted graphs. DFS (stack/recursion) detects cycles, performs topological sort on DAGs. Both are O(V+E).",b:"Adjacency list: O(V+E) space, good for sparse graphs. Adjacency matrix: O(V²) space, good for dense. BFS uses queue, level-order traversal — finds shortest path in unweighted graphs. DFS uses stack (or recursion call stack), can be used for maze solving, cycle detection (back edges), strongly connected components."},
{t:"Dijkstra's Algorithm",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"Dijkstra (1956) finds shortest paths from a source vertex to all others in graphs with non-negative weights. O((V+E) log V) with binary heap. Does not work with negative weights — use Bellman-Ford.",b:"Algorithm: maintain distance array (∞ initially), extract min from priority queue, relax neighbors (update if shorter path found via current vertex). Bellman-Ford handles negative weights (O(VE), detects negative cycles). A* algorithm extends Dijkstra with a heuristic for goal-directed search."},
{t:"QuickSort & MergeSort",c:"computer-science",src:[{t:"Algorithms (4th Edition)",tp:"book",y:2011,u:"https://algs4.cs.princeton.edu/",inst:"Princeton"}],tl:"QuickSort: average O(n log n), worst O(n²), in-place, not stable. Picks pivot, partitions, recurses. MergeSort: always O(n log n), stable, O(n) auxiliary space. Most practical sorts are hybrid (Timsort=merge+insertion).",b:"QuickSort pivot selection: median-of-three reduces worst-case probability. MergeSort is ideal for linked lists (no extra space for merge). Timsort (Python, Java, V8 JS) exploits natural runs in data: O(n) on already-sorted input. Comparison-based sorting lower bound: Ω(n log n). Non-comparison: counting sort, radix sort — O(n) when data range is limited."},
{t:"Dynamic Programming",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"DP solves problems by breaking them into overlapping subproblems, solving each once (memoization/tabulation). Converts exponential to polynomial time. Requires optimal substructure. Classic: Fibonacci, knapsack, LCS, edit distance.",b:"Top-down: recursion + cache (memoization). Bottom-up: iterative table filling (tabulation). 0/1 Knapsack: max value from n items with weight limit — O(nW) pseudo-polynomial. Longest Common Subsequence: O(mn). DP vs. greedy: greedy makes locally optimal choice (may fail globally); DP explores all possibilities via subproblem decomposition."},
{t:"Greedy Algorithms",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"Greedy algorithms make locally optimal choices hoping for global optimum. Fast but require correctness proof. Examples: Huffman coding, Prim/Kruskal (MST), activity selection, fractional knapsack.",b:"Greedy choice property: locally optimal choice leads to globally optimal solution. Proof via exchange argument: any optimal solution can be transformed to include the greedy choice. Prim's: grow MST by adding nearest vertex (O(E log V)). Kruskal's: sort edges, union-find to avoid cycles (O(E log E))."},
{t:"Time Complexity (Big O)",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"Big O describes upper bound of algorithm complexity as input size n grows. Common classes: O(1) constant, O(log n) logarithmic, O(n) linear, O(n log n) linearithmic, O(n²) quadratic, O(2ⁿ) exponential.",b:"Related: Ω (lower bound), Θ (tight bound). Amortized analysis: average over sequence of operations (e.g., dynamic array append is amortized O(1)). Master theorem solves divide-and-conquer recurrences T(n)=aT(n/b)+f(n). Space complexity matters too — quicksort is O(log n) space (recursion stack), mergesort is O(n) (auxiliary array)."},
{t:"Recursion",c:"computer-science",src:[{t:"Structure and Interpretation of Computer Programs (SICP)",tp:"book",y:1996,u:"https://mitpress.mit.edu/sites/default/files/sicp/",inst:"MIT Press"}],tl:"Recursion is a technique where a function calls itself to solve smaller instances of the same problem. It requires a base case (termination) and recursive case (problem reduction). Recursion elegantly models tree traversal, divide-and-conquer, and backtracking.",b:"Tail recursion: recursive call is the last operation — compilers can optimize to iteration (no stack growth). JavaScript engines (Safari JSC only) support TCO. Recursion depth limited by call stack (~10K in browsers). Recursion can always be converted to iteration (using explicit stack), and vice versa."},
{t:"Tree Data Structure",c:"computer-science",src:[{t:"Algorithms (4th Edition)",tp:"book",y:2011,u:"https://algs4.cs.princeton.edu/",inst:"Princeton"}],tl:"A tree is a hierarchical data structure with a root node and child subtrees. Each node (except root) has exactly one parent. Specialized trees: binary trees (max 2 children), N-ary trees, tries (prefix trees), segment trees (range queries), Fenwick trees (prefix sums).",b:"Binary tree properties: max nodes at level l = 2^l, max total nodes = 2^(h+1)-1. Full binary tree: every node has 0 or 2 children. Complete binary tree: all levels filled except possibly last. Perfect binary tree: all levels completely filled. Tries store strings character-by-character for O(k) lookup (k = key length)."},
{t:"Bit Manipulation",c:"computer-science",src:[{t:"Hacker's Delight (2nd Edition)",tp:"book",y:2012,u:"https://www.oreilly.com/library/view/hackers-delight-2nd/9780133084993/",inst:"Addison-Wesley"}],tl:"Bit manipulation operates directly on binary representations using bitwise operators: AND (&), OR (|), XOR (^), NOT (~), left shift (<<), right shift (>>). Used for optimization, cryptography, compression, hardware interfacing, and low-memory algorithms.",b:"Common tricks: n & (n-1) clears lowest set bit (used in popcount). n & 1 checks odd/even. XOR swap: a^=b; b^=a; a^=b. x XOR x = 0, x XOR 0 = x. Bitmask: single integer stores 32 boolean flags. Fast multiplication/division by powers of 2 via shift (compiler optimization)."},
{t:"String Matching Algorithms",c:"computer-science",src:[{t:"Introduction to Algorithms (CLRS)",tp:"book",y:2022,u:"https://mitpress.mit.edu/9780262046305/",inst:"MIT Press"}],tl:"String matching finds occurrences of a pattern in text. Naive: O(nm). KMP (Knuth-Morris-Pratt): O(n+m) using prefix function. Boyer-Moore: O(n/m) average, O(nm) worst. Rabin-Karp: O(n+m) average using rolling hash. Real-world text search uses hybrid algorithms.",b:"KMP precomputes failure function (longest proper prefix that is also suffix). Boyer-Moore scans pattern right-to-left, skipping characters — fastest in practice for English text. Aho-Corasick extends KMP for multiple pattern matching (used in fgrep, intrusion detection). Suffix arrays/trees enable O(m) substring search with O(n) preprocessing."},
].forEach(x=>{a.push(add(Object.assign({title:x.t,category:x.c,sources:x.src.map(s=>({title:s.t,...s})),tldr:x.tl,body:x.b},x)))});

// Design Patterns (10)
[
{t:"Singleton Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"Ensures a class has only one instance and provides global access. Used for shared resources: database connections, config, logging. Modern criticism: hidden global state, testing difficulty.",b:"Implementation: private constructor, static getInstance(). Thread-safe: double-checked locking, static initializer, or enum (Java). In JavaScript: module-level variable (modules are singletons by default). Dependency injection is often preferred over Singleton today."},
{t:"Factory Method Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"Defines an interface for creating objects, letting subclasses decide which class to instantiate. Defers instantiation to subclasses.",b:"Creator (abstract with factory method) + ConcreteCreator + Product interface. In modern code, factory functions (plain functions returning objects) often suffice without class hierarchies. Abstract Factory creates families of related objects (e.g., GUI widgets per platform)."},
{t:"Observer Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"One-to-many dependency — when subject changes, all observers are notified. Foundation of event-driven programming, MVC, React state updates, Redux.",b:"Subject maintains observer list and notify(). Push (pass data) vs. pull (observers query). JavaScript: EventEmitter pattern, addEventListener. React: setState triggers re-render (observer pattern with virtual DOM diffing). RxJS: Observable streams with operators (map, filter, debounce)."},
{t:"Strategy Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"Encapsulates interchangeable algorithms, making them swappable at runtime. Replaces large if-else chains with polymorphism. Example: sorting strategies, payment methods.",b:"Context (holds strategy), Strategy (interface), ConcreteStrategies. In functional languages, strategies are just functions — no class hierarchy needed. Key benefit: adding new strategies doesn't modify existing code (Open/Closed Principle)."},
{t:"Decorator Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"Attaches additional responsibilities dynamically, providing flexible alternative to subclassing. Decorators conform to the same interface, enabling transparent stacking.",b:"Example: `new CompressedStream(new EncryptedStream(new FileStream()))`. Python @decorator syntax. ES7 decorators (Stage 3). React HOC (Higher-Order Components) is a decorator pattern applied to components. Middleware pattern (Express, Koa) is a variant."},
{t:"Adapter Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"Converts interface of a class into another interface clients expect. Lets incompatible interfaces work together. Object adapter (composition) preferred over class adapter (inheritance).",b:"Example: wrapping a third-party logging library behind your application's Logger interface, enabling easy replacement. Adapter vs. Facade: Adapter changes interface; Facade simplifies a complex subsystem with a new unified interface. Bridge pattern separates abstraction from implementation."},
{t:"Command Pattern",c:"computer-science",src:[{t:"Design Patterns (Gang of Four)",tp:"book",y:1994,u:"https://www.oreilly.com/library/view/design-patterns-elements/0201633612/",inst:"Addison-Wesley"}],tl:"Encapsulates a request as an object, enabling parameterization, queuing, logging, and undo/redo. Commands are first-class objects with execute() and undo() methods.",b:"Example: text editor with undo stack — each edit is a Command object pushed to history. Macro commands compose multiple commands. Used in: job queues, transactional systems, game input handling. CQRS (Command Query Responsibility Segregation) extends this to architecture level."},
{t:"Model-View-Controller (MVC)",c:"computer-science",src:[{t:"Patterns of Enterprise Application Architecture",tp:"book",y:2002,u:"https://martinfowler.com/eaaCatalog/",inst:"Addison-Wesley"}],tl:"MVC separates application into three components: Model (data/business logic), View (presentation/UI), Controller (handles input, updates model). Originally from Smalltalk-80, MVC is the most influential architectural pattern in UI development.",b:"Variants: MVP (Model-View-Presenter), MVVM (Model-View-ViewModel, used by Vue, Angular). Web MVC: Ruby on Rails, Django, Laravel, Spring MVC. React is primarily the View layer but implements unidirectional data flow (Flux/Redux) rather than traditional MVC."},
{t:"Dependency Injection",c:"computer-science",src:[{t:"Inversion of Control Containers and the Dependency Injection pattern (Martin Fowler)",tp:"article",y:2004,u:"https://martinfowler.com/articles/injection.html"}],tl:"Dependency Injection (DI) is a technique where objects receive their dependencies from outside rather than creating them internally. It enables loose coupling, testability (mock dependencies), and centralized configuration.",b:"Types: constructor injection (preferred — immutable dependencies), setter injection (optional dependencies), interface injection. DI containers: Spring (Java), Angular, NestJS. Inversion of Control (IoC): the framework calls your code, not vice versa. DI is an implementation of IoC."},
{t:"Repository Pattern",c:"computer-science",src:[{t:"Patterns of Enterprise Application Architecture",tp:"book",y:2002,u:"https://martinfowler.com/eaaCatalog/",inst:"Addison-Wesley"}],tl:"The Repository pattern mediates between the domain and data mapping layers, acting like an in-memory collection of domain objects. It abstracts data access, enabling swapping data sources (database, API, in-memory) without changing business logic.",b:"Provides: collection-like interface (add, remove, find), query methods, separation from ORM. Often combined with Unit of Work pattern for transactional consistency. Generic repository: `Repository<T>` with common CRUD. Overuse can lead to anemic domain models — prefer rich domain models with behavior."},
].forEach(x=>{a.push(add(Object.assign({title:x.t,category:x.c,sources:x.src.map(s=>({title:s.t,...s})),tldr:x.tl,body:x.b},x)))});

// Cloud Computing & DevOps (15)
[
{t:"Amazon Web Services (AWS)",c:"computer-science",src:[{t:"AWS Documentation",tp:"documentation",y:2026,u:"https://docs.aws.amazon.com/",inst:"Amazon"}],tl:"AWS is the world's largest cloud provider, launched in 2006 with S3 and EC2. It offers 200+ services across compute, storage, database, ML, IoT, and serverless. AWS holds ~32% cloud market share (2025). Key services: EC2 (VMs), S3 (object storage), Lambda (serverless), DynamoDB (NoSQL), RDS (managed databases).",b:"Regions (geographic area, e.g., us-east-1) and Availability Zones (isolated data centers within region). Free Tier includes 750 hours/month EC2 t2.micro for 12 months. IAM controls access via users, roles, policies. Infrastructure as Code: CloudFormation, CDK. AWS was named after the river — not literally 'Amazon Web Services' in other contexts."},
{t:"Infrastructure as Code (IaC)",c:"computer-science",src:[{t:"Terraform Documentation",tp:"documentation",y:2026,u:"https://developer.hashicorp.com/terraform/docs",inst:"HashiCorp"}],tl:"IaC manages infrastructure through machine-readable definition files rather than manual configuration. Tools: Terraform (HCL, multi-cloud), Pulumi (general-purpose languages), CloudFormation (AWS-native), Ansible (configuration management). Version-controlled infrastructure enables reproducibility, code review, and automated testing.",b:"Declarative (Terraform: define desired state) vs. imperative (Ansible: define steps). Terraform state file tracks real-world resources — must be stored securely (S3 + DynamoDB locking). Modules enable reusable infrastructure components. Plan phase shows changes before apply. State drift: when real infrastructure differs from state file."},
{t:"CI/CD Pipeline",c:"computer-science",src:[{t:"Continuous Delivery (Jez Humble, David Farley)",tp:"book",y:2010,u:"https://www.oreilly.com/library/view/continuous-delivery-reliable/9780321670250/",inst:"Addison-Wesley"}],tl:"CI/CD automates software delivery: Continuous Integration (merge frequently, auto-test), Continuous Delivery (auto-deploy to staging), Continuous Deployment (auto-deploy to production). Core principle: every commit triggers pipeline → build → test → deploy. Reduces integration pain and speeds feedback loops.",b:"CI: automated builds + tests on every commit. CD: automated deployment after tests pass. Pipeline stages: lint, build, unit test, integration test, security scan, deploy to staging, smoke test, deploy to production. Tools: GitHub Actions, GitLab CI, Jenkins, CircleCI. Canary deployments: roll out to subset, monitor, expand. Blue-green: two identical environments, swap traffic."},
{t:"Docker Compose",c:"computer-science",src:[{t:"Docker Compose Documentation",tp:"documentation",y:2026,u:"https://docs.docker.com/compose/",inst:"Docker Inc."}],tl:"Docker Compose defines and runs multi-container Docker applications using a YAML file (`docker-compose.yml`). One command (`docker compose up`) starts all services. Ideal for development environments and single-host production deployments.",b:"Services, networks, volumes defined declaratively. `depends_on` controls startup order (but not readiness — use healthchecks). Environment variables via `.env` file or inline. Profiles enable conditional service activation. Compose v2 is written in Go (plugin). For multi-host, use Docker Swarm or Kubernetes."},
{t:"Monitoring and Observability",c:"computer-science",src:[{t:"Google SRE Book",tp:"book",y:2016,u:"https://sre.google/books/",inst:"Google"}],tl:"Monitoring tells you what's wrong; observability lets you ask why. Three pillars: metrics (numeric time-series, counters/gauges), logs (timestamped event records), traces (end-to-end request flow across services). The 'Golden Signals': latency, traffic, errors, saturation.",b:"Tools: Prometheus (metrics, pull-based), Grafana (dashboards), ELK/OpenSearch (logs), Jaeger/Zipkin (traces), OpenTelemetry (vendor-neutral instrumentation). SLOs (Service Level Objectives) define acceptable reliability: e.g., 99.9% availability with <100ms p99 latency. Alerting: alert on symptoms (user-facing impact), not causes. RED method: Rate, Errors, Duration per service."},
{t:"Load Balancing",c:"computer-science",src:[{t:"NGINX Documentation",tp:"documentation",y:2026,u:"https://nginx.org/en/docs/",inst:"NGINX Inc."}],tl:"A load balancer distributes incoming traffic across multiple backend servers, improving scalability, reliability (failover), and performance. Types: Layer 4 (TCP, fast, no content inspection), Layer 7 (HTTP, content-based routing, SSL termination).",b:"Algorithms: round-robin, least connections, IP hash (session persistence), weighted (unequal server capacity). Health checks probe backend availability. NGINX and HAProxy are the most popular software load balancers. Cloud-native: AWS ALB/NLB, GCP Cloud Load Balancing. Global server load balancing (GSLB) routes traffic across regions via DNS."},
{t:"Redis",c:"computer-science",src:[{t:"Redis Documentation",tp:"documentation",y:2026,u:"https://redis.io/docs/",inst:"Redis Ltd."}],tl:"Redis is an in-memory data structure store used as a database, cache, message broker, and streaming engine. It supports strings, hashes, lists, sets, sorted sets, bitmaps, hyperloglogs, geospatial indexes, and streams. Sub-millisecond latency, 100K+ ops/sec on modest hardware.",b:"Persistence: RDB (point-in-time snapshots) and AOF (append-only file log). Pub/Sub for messaging. Lua scripting for atomic operations. Redis Sentinel for high availability. Redis Cluster for horizontal sharding (16384 hash slots). Common patterns: session store, rate limiter, leaderboard, distributed lock (Redlock)."},
{t:"Nginx",c:"computer-science",src:[{t:"NGINX Documentation",tp:"documentation",y:2026,u:"https://nginx.org/en/docs/",inst:"NGINX Inc."}],tl:"Nginx is a high-performance web server, reverse proxy, and load balancer created by Igor Sysoev (2004) to solve the C10k problem (10,000 concurrent connections). Its event-driven, asynchronous architecture handles massive concurrency with minimal memory.",b:"Serves ~34% of all websites (2025). Key features: reverse proxy with caching, SSL/TLS termination, HTTP/2 and HTTP/3, WebSocket proxying, rate limiting, content compression. Configuration is declarative (nginx.conf). Nginx Unit runs apps in multiple languages. Nginx Plus (commercial) adds health checks, session persistence, and monitoring dashboard."},
{t:"API Gateway",c:"computer-science",src:[{t:"Kong Gateway Documentation",tp:"documentation",y:2026,u:"https://docs.konghq.com/",inst:"Kong Inc."}],tl:"An API Gateway is a single entry point for all client requests to a microservices architecture. It handles cross-cutting concerns: authentication, rate limiting, request routing, protocol translation, caching, logging, and API composition.",b:"Popular gateways: Kong (Lua/OpenResty), AWS API Gateway, Azure API Management, Apigee, Envoy (Lyft, graduated CNCF). BFF (Backend for Frontend) pattern: dedicated gateway per client type. API Gateway vs. Service Mesh: gateway handles north-south traffic (client→server); service mesh handles east-west (service→service)."},
{t:"Microservices Architecture",c:"computer-science",src:[{t:"Building Microservices (2nd Edition, Sam Newman)",tp:"book",y:2021,u:"https://www.oreilly.com/library/view/building-microservices-2nd/9781492034018/",inst:"O'Reilly"}],tl:"Microservices architectural style structures an application as a collection of loosely coupled, independently deployable services. Each service owns its data, communicates via APIs, and can be developed/deployed/scaled independently. Contrasts with monolithic architecture (all-in-one).",b:"Key principles: decentralized data management (each service has its own database), smart endpoints/dumb pipes, design for failure (circuit breakers, retries, bulkheads). Challenges: distributed complexity, network latency, data consistency (eventual consistency), service discovery. When NOT to use microservices: early-stage products, small teams, simple domains."},
{t:"Serverless Computing",c:"computer-science",src:[{t:"AWS Lambda Documentation",tp:"documentation",y:2026,u:"https://docs.aws.amazon.com/lambda/",inst:"Amazon"}],tl:"Serverless computing abstracts away server management — developers write and deploy functions; the cloud provider handles provisioning, scaling, and maintenance. Pay-per-request model (no idle cost). AWS Lambda (2014) pioneered the model; others: Azure Functions, Google Cloud Functions, Cloudflare Workers.",b:"FaaS (Functions as a Service) is the core of serverless. Cold start: first invocation after idle period has latency penalty (provisioned concurrency mitigates). Stateless by design — state must be externalized (DynamoDB, S3). Event-driven: triggered by HTTP, S3 uploads, queue messages, cron schedules. Serverless is NOT 'no servers' — it's 'no servers YOU manage'."},
{t:"Kubernetes Pod & Service",c:"computer-science",src:[{t:"Kubernetes Documentation",tp:"documentation",y:2026,u:"https://kubernetes.io/docs/",inst:"CNCF"}],tl:"A Pod is the smallest deployable unit in Kubernetes — one or more containers sharing network namespace, IPC, and storage volumes. A Service provides stable networking — a virtual IP (ClusterIP) and DNS name that load-balances across Pod replicas, surviving Pod restarts.",b:"Pod lifecycle: Pending → Running → Succeeded/Failed. Init containers run before app containers. Sidecar pattern: helper container alongside main (logging, proxying). Service types: ClusterIP (internal only), NodePort (exposes on node IP), LoadBalancer (cloud provider LB). Ingress routes external HTTP traffic to Services."},
{t:"GitHub Actions",c:"computer-science",src:[{t:"GitHub Actions Documentation",tp:"documentation",y:2026,u:"https://docs.github.com/en/actions",inst:"GitHub"}],tl:"GitHub Actions is a CI/CD platform integrated into GitHub repositories. Workflows (YAML files in `.github/workflows/`) trigger on events (push, PR, schedule) and execute jobs on runners (Ubuntu, Windows, macOS). Free for public repositories.",b:"Workflow syntax: `on:` defines triggers, `jobs:` defines steps. Runners: GitHub-hosted (2-core, 7GB RAM, free for public) or self-hosted. Marketplace: community-built actions (checkout, setup-node, deploy). Matrix builds: test across multiple versions/OS combinations. Secrets: encrypted environment variables (`${{ secrets.TOKEN }}`)."},
{t:"Terraform",c:"computer-science",src:[{t:"Terraform Documentation",tp:"documentation",y:2026,u:"https://developer.hashicorp.com/terraform/docs",inst:"HashiCorp"}],tl:"Terraform by HashiCorp is the dominant Infrastructure as Code tool, using HCL (HashiCorp Configuration Language) to declaratively define and provision cloud resources across 3000+ providers. State file tracks real-world resources; plan shows pending changes.",b:"`terraform init` (download providers), `plan` (preview changes), `apply` (provision), `destroy` (teardown). Remote state (S3 + DynamoDB) for team collaboration and state locking. Modules enable reusable configuration. Workspaces isolate environments. Terraform Cloud/Enterprise adds VCS integration, policy as code (Sentinel), and cost estimation."},
{t:"Prometheus",c:"computer-science",src:[{t:"Prometheus Documentation",tp:"documentation",y:2026,u:"https://prometheus.io/docs/",inst:"CNCF"}],tl:"Prometheus is the de facto open-source monitoring and alerting system, graduated from CNCF. It scrapes metrics from instrumented targets via HTTP, stores time-series data locally, and provides a powerful query language (PromQL). Paired with Grafana for visualization and Alertmanager for notifications.",b:"Pull-based model: Prometheus server scrapes targets at intervals (15s default). Instrumentation: client libraries expose /metrics endpoint. PromQL: `rate(http_requests_total[5m])`, `histogram_quantile(0.99, ...)`. Service discovery auto-detects targets (Kubernetes, Consul, EC2). Limitations: single-node, not suitable for long-term storage (use Thanos/Cortex for that)."},
].forEach(x=>{a.push(add({title:x.t,category:x.c,sources:x.src.map(s=>({title:s.t||s.title,type:s.tp||s.type||"documentation",year:s.y||s.year,url:s.u||s.url,inst:s.inst})),tldr:x.tl,body:x.b}))});

// More Web & Programming (15)
[
{t:"CSS Flexbox",c:"computer-science",src:[{t:"CSS Flexible Box Layout Module Level 1 (W3C)",tp:"standard",y:2018,u:"https://www.w3.org/TR/css-flexbox-1/",inst:"W3C"}],tl:"Flexbox provides one-dimensional layout (row or column), distributing space and aligning items within a container. `display: flex` on parent enables flex context. Key properties: `justify-content` (main axis alignment), `align-items` (cross axis), `flex-grow/shrink/basis` (item sizing).",b:"Flex container properties: `flex-direction` (row|column), `flex-wrap` (wrap|nowrap), `gap`. Flex item: `flex: grow shrink basis` shorthand. `align-self` overrides cross-axis alignment per item. `order` changes visual order without HTML changes. Flexbox is ideal for navigation bars, card layouts, centering, and distributing space in one dimension."},
{t:"CSS Grid",c:"computer-science",src:[{t:"CSS Grid Layout Module Level 2 (W3C)",tp:"standard",y:2024,u:"https://www.w3.org/TR/css-grid-2/",inst:"W3C"}],tl:"CSS Grid provides two-dimensional layout (rows AND columns). `display: grid` enables grid context. `grid-template-columns/rows` define tracks. `fr` unit distributes remaining space. Grid excels at page-level layouts, dashboards, and any design needing both row and column control.",b:"`grid-template-areas` enables named visual areas: `header header; sidebar main; footer footer`. `grid-column/grid-row` span items across tracks. `auto-fill/auto-fit` with `minmax()` creates responsive grids without media queries. Subgrid (Level 2) enables nested grids to align with parent grid tracks. Flexbox vs. Grid: Flexbox for components, Grid for page layout."},
{t:"HTML5 Semantic Elements",c:"computer-science",src:[{t:"HTML Living Standard",tp:"standard",y:2026,u:"https://html.spec.whatwg.org/",inst:"WHATWG"}],tl:"HTML5 (2014) introduced semantic elements that describe their meaning to both browser and developer: `<header>`, `<nav>`, `<main>`, `<article>`, `<section>`, `<aside>`, `<footer>`, `<figure>`, `<time>`. They improve accessibility (screen readers), SEO, and code readability.",b:"`<main>` should be used once per page (dominant content). `<article>` for self-contained, independently distributable content. `<section>` for thematic grouping with a heading. `<aside>` for tangentially related content. Semantic HTML provides implicit ARIA roles — `<nav>` = role='navigation', `<main>` = role='main'. Always prefer semantic elements over `<div>`."},
{t:"ARIA (Accessible Rich Internet Applications)",c:"computer-science",src:[{t:"WAI-ARIA 1.2 (W3C Recommendation)",tp:"standard",y:2023,u:"https://www.w3.org/TR/wai-aria/",inst:"W3C"}],tl:"ARIA provides attributes that enhance HTML accessibility for assistive technologies (screen readers). It defines roles (`role='button'`), states (`aria-expanded`), and properties (`aria-label`). The first rule of ARIA: don't use ARIA if native HTML already provides the semantics.",b:"Key patterns: `aria-label` for accessible names, `aria-labelledby` to reference another element, `aria-describedby` for descriptions, `aria-live` for dynamic content announcements (polite/assertive). `role='alert'` for important notifications. ARIA does NOT change behavior — `role='button'` doesn't add click handling or keyboard interaction."},
{t:"Web Performance Optimization",c:"computer-science",src:[{t:"Web Vitals (Google)",tp:"documentation",y:2024,u:"https://web.dev/vitals/",inst:"Google"}],tl:"Web performance optimization reduces page load time and improves user experience. Core Web Vitals: LCP (Largest Contentful Paint, <2.5s), INP (Interaction to Next Paint, <200ms, replaces FID in 2024), CLS (Cumulative Layout Shift, <0.1). These metrics directly affect Google search rankings.",b:"Optimization techniques: code splitting (dynamic imports), tree shaking (remove unused code), image optimization (WebP/AVIF, srcset, lazy loading), font optimization (font-display: swap, subsetting), CDN, compression (Brotli), caching (Cache-Control headers), critical CSS inlining. Lighthouse and PageSpeed Insights measure and guide improvements."},
{t:"Progressive Web Apps (PWA)",c:"computer-science",src:[{t:"Progressive Web Apps (MDN)",tp:"documentation",y:2025,u:"https://developer.mozilla.org/en-US/docs/Web/Progressive_web_apps",inst:"Mozilla"}],tl:"PWAs are web applications that use modern APIs to deliver app-like experiences: installable (manifest.json), offline-capable (Service Workers), push notifications, and background sync. PWAs work across platforms from a single codebase.",b:"Requirements: HTTPS, Web App Manifest (name, icons, start_url, display: standalone), registered Service Worker with fetch handler. App shell architecture: cache shell (UI), fetch content dynamically. Workbox (Google) simplifies Service Worker management. PWAs can be distributed via app stores (Trusted Web Activity on Android)."},
{t:"Responsive Web Design",c:"computer-science",src:[{t:"Responsive Web Design (Ethan Marcotte)",tp:"article",y:2010,u:"https://alistapart.com/article/responsive-web-design/"}],tl:"Responsive Web Design (RWD) creates websites that adapt to any screen size using fluid grids, flexible images, and CSS media queries. Coined by Ethan Marcotte (2010), RWD is now the standard approach for web development.",b:"Mobile-first: design for smallest screen first, progressively enhance for larger. Media queries: `@media (min-width: 768px)`. Container queries (2023+): style based on parent container size, not viewport. Fluid typography: `clamp(1rem, 2vw, 2rem)`. Viewport meta tag: `<meta name='viewport' content='width=device-width,initial-scale=1'>`."},
{t:"Package Managers (npm, yarn, pnpm)",c:"computer-science",src:[{t:"npm Documentation",tp:"documentation",y:2026,u:"https://docs.npmjs.com/",inst:"npm Inc."}],tl:"Package managers automate dependency installation, version management, and script execution. npm (Node Package Manager) is the default for Node.js with 2M+ packages. Yarn (Facebook, 2016) added deterministic installs via lockfiles. pnpm (2017) saves disk space via content-addressable storage (symlinked node_modules).",b:"`package.json`: dependencies (runtime), devDependencies (build/test), peerDependencies (host provides), optionalDependencies. Semantic versioning (semver): MAJOR.MINOR.PATCH. `^1.2.3` allows minor/patch updates; `~1.2.3` allows patch only. `package-lock.json` pins exact versions for reproducible builds. `npx` runs packages without installing."},
{t:"Webpack",c:"computer-science",src:[{t:"Webpack Documentation",tp:"documentation",y:2025,u:"https://webpack.js.org/",inst:"OpenJS Foundation"}],tl:"Webpack is a module bundler that transforms frontend assets (JS, CSS, images) into optimized bundles. Entry point → dependency graph → loaders (transform files) → plugins (optimize output) → bundles. Introduced code splitting and hot module replacement to mainstream JavaScript.",b:"Loaders: `babel-loader` (transpile), `css-loader`, `file-loader`. Plugins: `HtmlWebpackPlugin`, `MiniCssExtractPlugin`, `TerserPlugin` (minification). Webpack 5 (2020): module federation (sharing modules across applications). Newer alternatives: Vite (ESM-native, faster dev server), esbuild (Go, 10-100x faster), Turbopack (Rust, Next.js)."},
{t:"Vite",c:"computer-science",src:[{t:"Vite Documentation",tp:"documentation",y:2026,u:"https://vitejs.dev/",inst:"VoidZero Inc."}],tl:"Vite (Evan You, 2020) is a next-generation frontend build tool that leverages native ES modules for instant dev server startup and HMR. Uses esbuild for pre-bundling (10-100x faster than Webpack) and Rollup for production builds.",b:"Dev server: serves source files natively via ESM, no bundling needed — HMR in <1ms. Production: Rollup for optimized tree-shaken output. Framework-agnostic: React, Vue, Svelte, Solid via plugins. `import.meta.glob()` for dynamic imports. Vite 6 (2024): Environment API, improved SSR. Has largely replaced Webpack in new projects."},
{t:"ESLint",c:"computer-science",src:[{t:"ESLint Documentation",tp:"documentation",y:2026,u:"https://eslint.org/docs/",inst:"OpenJS Foundation"}],tl:"ESLint is a static analysis tool for JavaScript/TypeScript that identifies problematic patterns and enforces coding standards. Created by Nicholas Zakas (2013), it is the most popular JS linter. ESLint 9 (2024) introduced flat config (`eslint.config.mjs`), replacing `.eslintrc`.",b:"Rules can be: off (0), warn (1), error (2). Plugins extend rules (eslint-plugin-react, @typescript-eslint). Prettier handles formatting (complementary, not competing — use eslint-config-prettier to disable conflicting rules). Autofix: `eslint --fix` automatically corrects fixable issues (indentation, semicolons, unused imports)."},
{t:"Prettier",c:"computer-science",src:[{t:"Prettier Documentation",tp:"documentation",y:2026,u:"https://prettier.io/docs/",inst:"Prettier"}],tl:"Prettier is an opinionated code formatter supporting JavaScript, TypeScript, CSS, HTML, JSON, Markdown, YAML, and more. It enforces consistent formatting by parsing code and re-printing it with its own rules. Minimizes bike-shedding in code reviews.",b:"Key philosophy: limited configurability (by design) — fewer options = less debate. `.prettierrc` controls the few options available: `tabWidth`, `semi`, `singleQuote`, `trailingComma`, `printWidth`. `.prettierignore` excludes files. Integrates with ESLint (eslint-config-prettier), editors (format-on-save), and pre-commit hooks (lint-staged + husky)."},
{t:"Testing Pyramid",c:"computer-science",src:[{t:"Succeeding with Agile (Mike Cohn)",tp:"book",y:2009,u:"https://www.mountaingoatsoftware.com/books/succeeding-with-agile",inst:"Addison-Wesley"}],tl:"The Testing Pyramid (Mike Cohn) describes the optimal distribution of test types: many fast unit tests at the base, fewer integration tests in the middle, few slow E2E tests at the top. The Anti-Pattern: inverted pyramid (ice cream cone) — many E2E tests, few unit tests.",b:"Unit tests: test individual functions/components in isolation, milliseconds, run on every commit. Integration tests: test multiple units together (API + DB), seconds. E2E tests: test full user flows through browser (Cypress, Playwright), minutes, run on deploy. Coverage metrics: line, branch, function — 100% coverage ≠ bug-free. Test behavior, not implementation."},
{t:"Cypress",c:"computer-science",src:[{t:"Cypress Documentation",tp:"documentation",y:2026,u:"https://docs.cypress.io/",inst:"Cypress.io"}],tl:"Cypress is a JavaScript end-to-end testing framework that runs directly in the browser, providing real-time reloading, automatic waiting, and time-travel debugging. It competes with Selenium and Playwright. Cypress runs in the same event loop as the application.",b:"Key features: automatic retries and waiting (no `sleep()`), screenshots and videos of test runs, component testing (Cypress 10+, mounts React/Vue components), network stubbing (`cy.intercept()`). No multi-tab or multi-browser support (this is by design — Cypress runs in a single browser instance). Playwright (Microsoft) is the main alternative with multi-browser support."},
{t:"Playwright",c:"computer-science",src:[{t:"Playwright Documentation",tp:"documentation",y:2026,u:"https://playwright.dev/",inst:"Microsoft"}],tl:"Playwright is a cross-browser automation library by Microsoft enabling reliable end-to-end testing across Chromium, Firefox, and WebKit with a single API. Unlike Cypress, Playwright runs outside the browser as a Node.js process, supporting multiple tabs, iframes, and native mobile emulation.",b:"Key features: auto-waiting for elements, trace viewer (debug test failures), test generator (`codegen` records actions), API testing (same syntax for UI and API), mobile device emulation (iPhone, Pixel). Supports JavaScript, TypeScript, Python, .NET, Java. Playwright has the most comprehensive cross-browser coverage of any testing tool."},
].forEach(x=>{a.push(add({title:x.t,category:x.c,sources:x.src.map(s=>({title:s.t||s.title,type:s.tp||s.type||"documentation",year:s.y||s.year,url:s.u||s.url,inst:s.inst})),tldr:x.tl,body:x.b}))});

